import React from 'react';
import ProjectList from './../components/ProjectList';
import Sidebar from './../components/Sidebar';

function Home() {
  return(
    <div>
      <Sidebar />
    	<main id="main">
    		<div className="main-outer">
    			<div className="container-fluid">
    				<div className="row">
    					<div className="col-md-12">
    						<div id="works-grid">
    							<ProjectList />
    						</div>
    					</div>
    				</div>
    			</div>
    		</div>
    	</main>
    </div>
  );
}
export default Home;
